<?php
use admin\logic\Product\ProductPrice;
use Admin_Model_CartLog as CartLog;
use common\logic\Eshop\Eshop;
use user\logic\UserClientSession;
use user\logic\UserSettings;
use Common_Model_Eshop as EshopModel;

/**
 * Admin_Model_Cart
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 * 
 * @package    ##PACKAGE##
 * @subpackage ##SUBPACKAGE##
 * @author     ##NAME## <##EMAIL##>
 * @version    SVN: $Id: Builder.php 7490 2010-03-29 19:53:27Z jwage $
 */
class Admin_Model_Cart extends Admin_Model_Base_Cart {

    const CART_HASH = 'cartHash';

    /**
     * @param int|null $userID
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getCartItems(?int $userID, Eshop $eshop = null): array {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Cart object');
        $query->addSelect('object.*, product.*, productStocks.*, productEshops.*, vat.*, productLangs.*, productLangs.Name as ProductName, productImages.*, file.*, categories.*');
        $query->addSelect('productLangs.Name as ProductName, productLangs.slug as slug');
        $query->addSelect('GROUP_CONCAT(categories.Category_ID SEPARATOR ",") as CategoryIDs');
        if ( $userID )
            $query->andWhere('object.User_ID = ?', $userID);
        $query->andWhere('object.SessionID = ?', self::getCookieId());
        $query->leftJoin('object.product product');
        $query->leftJoin('product.productEshops productEshops WITH productEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('productEshops.vat vat');
        $query->leftJoin('product.productLangs productLangs WITH productLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('product.productImages productImages WITH productImages.Main = true');
        $query->leftJoin('product.categories categories');
        $query->leftJoin('product.productStocks productStocks');
        $query->leftJoin('productImages.file file');
        $query->addWhere('object.Coupon_ID IS NULL');
        $query->addGroupBy('object.Product_ID, productEshops.ID');
        $cartItems = $query->execute()->toArray();

        foreach ( $cartItems as &$cartItem ) {
            $cartItem['product'] ['CategoryIDs'] = $cartItem['CategoryIDs'];
            $productPrice = new ProductPrice($cartItem['product'], UserSettings::getInstance($userID)->getValue('Discount'), UserSettings::getInstance()->getGroupDiscounts(), $cartItem['Quantity']);
            $cartItem['product'] = $productPrice->getProduct();
            $cartItem['product']['TotalQuantity'] = 0;
            foreach( $cartItem['product']['productStocks'] as &$productStock) {
                $cartItem['product']['TotalQuantity'] += $productStock['Quantity'];
            }
        }

        return $cartItems;
    }

    /**
     * empty Cart
     * @param null $userID
     * @param Eshop|null $eshop
     */
    public static function emptyCart($userID = null, Eshop $eshop = null) {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_Cart object');
        if ( $userID  )
            $query->where('object.User_ID = ?', $userID);
        else
            $query->where('object.SessionID = ?', self::getCookieId());
        $query->andWhere('object.Cart_ID IS NOT NULL');
        $query->andWhere('object.Eshop_ID = ?', $eshop->ID);
        $query->execute();

        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_Cart object');
        if ( $userID  )
            $query->where('object.User_ID = ?', $userID);
        else
            $query->where('object.SessionID = ?', self::getCookieId());
        $query->andWhere('object.Eshop_ID = ?', $eshop->ID);
        $query->execute();
    }

    /**
     * @param int|null $userID
     * @param int $productID
     * @param Eshop|null $eshop
     * @return bool|Admin_Model_Cart
     */
    public static function getCartByProductID(?int $userID, int $productID, Eshop $eshop = null): bool|Admin_Model_Cart {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Cart object');
        $query->where('object.Product_ID = ?', $productID);

        if ( $userID )
            $query->andWhere('object.User_ID = ?', $userID);
        else
            $query->andWhere('object.SessionID = ?', self::getCookieId());
        $query->andWhere('object.Eshop_ID = ?', $eshop->ID);

        return $query->fetchOne();
    }

    /**
     * @param ?int $userID
     * @param int $productID
     * @param int $quantity
     * @param bool $assignQuantity
     * @param Admin_Model_Cart|bool|null $cartItem
     * @param int|null $parrentCartItemID
     * @param Eshop|null $eshop
     * @return Admin_Model_Cart
     */
    public static function createCart(?int $userID, int $productID, int $quantity, bool $assignQuantity = false, Admin_Model_Cart|bool|null $cartItem = false, int $parrentCartItemID = null, Eshop $eshop = null) : Admin_Model_Cart {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        if ( $cartItem ) {
            $cartItem->Quantity = $assignQuantity ? $quantity : $cartItem->Quantity + $quantity;
        } else {
            $cartItem = new Admin_Model_Cart();
            $cartItem->Product_ID = $productID;
            $cartItem->Quantity = $quantity;
            $cartItem->Code = generateRandomString(10);
            $cartItem->Eshop_ID = $eshop->ID;
        }

        if ( $userID )
            $cartItem->User_ID = $userID;

        if ( $parrentCartItemID )
            $cartItem->Cart_ID = $parrentCartItemID;

        $cartItem->SessionID = self::getCookieId();
        $cartItem->Date = date('Y-m-d');
        $cartItem->Time = date('H:i');
        $cartItem->save();

        CartLog::creteCartLog($productID, $userID, $quantity);

        return $cartItem;
    }

    /**
     * @param int|null $userID
     * @param int $productID
     * @param Eshop|null $eshop
     */
    public static function deleteCartProduct(?int $userID, int $productID, Eshop $eshop = null) {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_Cart object');
        $query->where('object.Product_ID = ?', $productID);

        if ( $userID )
            $query->andWhere('object.User_ID = ?', $userID);
        else
            $query->andWhere('object.SessionID = ?', self::getCookieId());
        $query->andWhere('object.Eshop_ID = ?', $eshop->ID);
        $query->execute();
    }

    /**
     * @param Eshop|null $eshop
     */
    public static function updateCartAfterLogin(Eshop $eshop = null) {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $userID = UserClientSession::getCurrentUserID();

        $query = Doctrine_Query::create();
        $query->update('Admin_Model_Cart object');
        $query->set('object.User_ID', '?', $userID);
        $query->where('object.SessionID = ?', self::getCookieId());
        $query->andWhere('object.Eshop_ID = ?', $eshop->ID);
        $query->execute();
    }

    /**
     * @return int
     */
    public static function getTodayCarts(): int {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Cart object');
        $query->where('object.Date = ?', date('Y-m-d'));
        $query->addGroupBy('object.User_ID');

        return count($query->execute()->toArray());
    }

    /**
     * @return string
     */
    public static function getCookieId(): string {
        return $_COOKIE[self::CART_HASH] ?? self::getNewCookieId();
    }

    /**
     * @return string
     */
    protected static function getNewCookieId(): string {
        setcookie(self::CART_HASH, $id = md5(time()), strtotime('+30 day'), '/', null, false, true);

        return $id;
    }

    /**
     * Vrací užitý kupón
     * @param int|null $userID
     * @param EshopModel|null $eshop
     * @return Admin_Model_Coupon|null
     */
    public static function getCartCoupon(?int $userID, ?EshopModel $eshop = null): ?Admin_Model_Coupon {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Cart object');
        $query->where('object.Coupon_ID IS NOT NULL');
        $query->addWhere('object.Eshop_ID = ?', $eshop->ID);
        if ( $userID )
            $query->andWhere('object.User_ID = ?', $userID);
        else
            $query->andWhere('object.SessionID = ?', self::getCookieId());

        $query->innerJoin('object.coupon coupon');
        $query->orderBy('object.ID DESC');
        /** @var self $cart */
        $cart = $query->fetchOne();

        if ($cart && $cart->coupon)
            return $cart->coupon;

        return null;
    }

    /**
     * @param string|int|null $userID
     * @param string $CouponCode
     * @param int|float|null $order
     * @param EshopModel|null $eshop
     * @return null|Admin_Model_Cart
     * @throws Exception
     */
    public static function applyCoupon($userID, string $CouponCode, $order = null, ?EshopModel $eshop = null): ?Admin_Model_Cart {
        $coupon = Admin_Model_Coupon::getCouponByCode($CouponCode, $order);

        if ($coupon) {
            if ( !$eshop )
                $eshop = Eshop::getInstance()->getEshop();

            $cartItem = new Admin_Model_Cart();
            $cartItem->Coupon_ID = $coupon->ID;
            $cartItem->Eshop_ID = $eshop->ID;
            $cartItem->Quantity = 1;
            $cartItem->Code = generateRandomString();

            if ( $userID )
                $cartItem->User_ID = $userID;

            $cartItem->SessionID = self::getCookieId();
            $cartItem->Date = date('Y-m-d');
            $cartItem->Time = date('H:i');
            $cartItem->save();

            return $cartItem;
        } else {
            return null;
        }
    }

    /**
     * @param string|int|null $userID
     * @param EshopModel|null $eshop
     * @throws Doctrine_Query_Exception
     */
    public static function deleteCartCoupon($userID, ?EshopModel $eshop = null) {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_Cart object');
        $query->where('object.Coupon_ID IS NOT NULL');
        $query->andWhere('object.Eshop_ID = ?', $eshop->ID);

        if ( $userID )
            $query->andWhere('object.User_ID = ?', $userID);
        else
            $query->andWhere('object.SessionID = ?', self::getCookieId());

        $query->execute();
    }
}